<script setup>
import Checkbox from '@/Components/Checkbox.vue';
import InputError from '@/Components/InputError.vue';
import { Head, Link, useForm } from '@inertiajs/vue3';

defineProps({
    canResetPassword: { type: Boolean },
    status: { type: String },
});

const form = useForm({
    email: '',
    password: '',
    remember: false,
});

const submit = () => {
    form.post(route('login'), {
        onFinish: () => form.reset('password'),
    });
};
</script>

<template>
    <Head title="Iniciar Sesión — Pozo SAEMIF" />

    <div class="login-root">

        <!-- Fondo animado con ondas -->
        <div class="bg-overlay">
            <div class="wave wave1"></div>
            <div class="wave wave2"></div>
            <div class="wave wave3"></div>
            <div class="bubbles">
                <span></span><span></span><span></span>
                <span></span><span></span><span></span>
            </div>
        </div>

        <!-- Card central -->
        <div class="login-card">

            <!-- Logo -->
            <div class="logo-wrap">
                <img src="data:image/png;base64," alt="Purificadora SAEMIF" class="logo-img" />
            </div>

            <h1 class="title">Bienvenido</h1>
            <p class="subtitle">Accede al sistema de gestión</p>

            <div v-if="status" class="status-msg">{{ status }}</div>

            <form @submit.prevent="submit" class="login-form">

                <div class="field-group">
                    <label for="email">Correo electrónico</label>
                    <div class="input-wrap">
                        <span class="input-icon">✉</span>
                        <input id="email" v-model="form.email" type="email"
                               placeholder="usuario@saemif.com"
                               required autofocus autocomplete="username" />
                    </div>
                    <InputError :message="form.errors.email" />
                </div>

                <div class="field-group">
                    <label for="password">Contraseña</label>
                    <div class="input-wrap">
                        <span class="input-icon">🔒</span>
                        <input id="password" v-model="form.password" type="password"
                               placeholder="••••••••"
                               required autocomplete="current-password" />
                    </div>
                    <InputError :message="form.errors.password" />
                </div>

                <div class="remember-row">
                    <label class="remember-label">
                        <Checkbox name="remember" v-model:checked="form.remember" />
                        <span>Recordarme</span>
                    </label>
                    <Link v-if="canResetPassword" :href="route('password.request')" class="forgot-link">
                        ¿Olvidaste tu contraseña?
                    </Link>
                </div>

                <button type="submit" class="btn-login" :disabled="form.processing">
                    <span v-if="form.processing">Ingresando...</span>
                    <span v-else>Ingresar al Sistema</span>
                </button>

            </form>

            <p class="footer-text">Purificadora SAEMIF · Cuidamos tu salud</p>
        </div>
    </div>
</template>

